window.addEventListener('message', function(event) {
  if (event.data && event.data.type === 'EMBED_CONTEXT') {
    // Store the Ozone access token
    actions.setVariable('access_token', event.data.access_token);

    // Store any other custom params
    const { type, access_token, ...customParams } = event.data;

    Object.entries(customParams).forEach(([key, value]) => {
      actions.setVariable(key, value); 
  }

  return event.data.access_token
});
